class EventEmitter:
    def __init__(self):
        self._listeners: Dict[str, List[Callable]] = {}

    def on(self, event: str, callback: Callable) -> None:
        if event not in self._listeners:
            self._listeners[event] = []
        self._listeners[event].append(callback)

    def off(self, event: str, callback: Callable) -> None:
        if event in self._listeners:
            try:
                # Check if the callback is a wrapper created by once. If so, we should remove it directly, 
                # but general off must handle standard callbacks too.
                self._listeners[event].remove(callback)
            except ValueError:
                pass

    def once(self, event: str, callback: Callable) -> None:
        def wrapper(*args: any):
            try:
                callback(*args)
            finally:
                # When the wrapper executes, it removes itself from the list.
                self.off(event, wrapper)

        self.on(event, wrapper)

    def emit(self, event: str, *args: any) -> None:
        if event in self._listeners:
            # We must iterate over a copy because listeners might modify the list during execution (e.g., via once's wrapper).
            for callback in list(self._listeners[event]): 
                try:
                    callback(*args)
                except Exception as e:
                    print(f"Error executing listener for event '{event}': {e}")

